function getSelectedChildSpouseId() {
  if (!childWifeSelect) return null;
  const v = String(childWifeSelect.value || "").trim();
  if (!v) return null;
  const n = Number(v);
  return Number.isFinite(n) && n > 0 ? n : null;
}
function parseWifeFamilyValue() {
  const v = wifeFamily ? String(wifeFamily.value || "").trim() : "";
  if (v === "true") return true;
  if (v === "false") return false;
  return null;
}
function setWifeAlert(type, text) {
  if (!wifeAlert) return;
  wifeAlert.textContent = text || "";
  wifeAlert.className = "alert " + (type === "success" ? "alert-success" : "alert-error");
  wifeAlert.style.display = text ? "block" : "none";
}
async function getTreePersonIdByName(sb, fullName) {
  const name = normalizePersonName(fullName || "");
  if (!sb || !name) return null;
  const r = await sb.from("tree_children").select("id,name").eq("name", name).limit(1).maybeSingle();
  if (r.error || !r.data || r.data.id == null) return null;
  return r.data.id;
}
function renderWivesRows(rows) {
  if (!wivesList) return;
  const list = Array.isArray(rows) ? rows : [];
  wivesList.innerHTML = "";
  if (childWifeSelect) {
    childWifeSelect.innerHTML = '<option value="">بدون ربط أم الآن</option>';
  }
  if (!list.length) {
    const empty = document.createElement("div");
    empty.className = "hint";
    empty.textContent = "لا توجد زوجات مسجلة لهذا الأب حالياً.";
    wivesList.appendChild(empty);
    return;
  }
  list.forEach((row) => {
    const wifeId = row.id;
    const wifeText = normalizePersonName(row.wife_name || "");
    if (childWifeSelect && wifeId != null) {
      const opt = document.createElement("option");
      opt.value = String(wifeId);
      opt.textContent = wifeText || ("زوجة رقم " + String(wifeId));
      childWifeSelect.appendChild(opt);
    }
    const item = document.createElement("div");
    item.className = "child-row";
    item.style.display = "flex";
    item.style.justifyContent = "space-between";
    item.style.gap = "10px";
    item.style.flexWrap = "wrap";
    const info = document.createElement("div");
    info.innerHTML =
      '<strong>' + (wifeText || "بدون اسم") + '</strong>' +
      '<div class="hint">الترتيب: ' + (row.marriage_order || "غير محدد") +
      ' — الأبناء المرتبطون: ' + (row.linked_children_count || 0) + '</div>';
    item.appendChild(info);
    wivesList.appendChild(item);
  });
}
async function loadWivesForSelectedParent() {
  if (!state.branch || !parentSelect) return;
  const sb = getالخدمةClient();
  if (!sb) return;
  const parentName = resolveSelectedParentId(normalizePersonName(parentSelect.value), state.branch);
  if (!parentName) {
    renderWivesRows([]);
    return;
  }
  const husbandId = await getTreePersonIdByName(sb, parentName);
  if (!husbandId) {
    renderWivesRows([]);
    return;
  }
  const r = await sb
    .from("tree_spouse_summary")
    .select("id,husband_id,wife_name,wife_branch_key,wife_lineage,marriage_order,status,confidence,linked_children_count")
    .eq("husband_id", husbandId)
    .order("marriage_order", { ascending: true })
    .order("id", { ascending: true });
  if (r.error) {
    setWifeAlert("error", "تعذر تحميل الزوجات: " + (r.error.message || "خطأ غير معروف"));
    return;
  }
  renderWivesRows(r.data || []);
}
async function saveWifeForSelectedParent() {
  if (!state.branch) {
    setWifeAlert("error", "يلزم تسجيل دخول المندوب أولاً.");
    return;
  }
  const sb = getالخدمةClient();
  if (!sb) {
    setWifeAlert("error", "تعذر الاتصال بقاعدة البيانات.");
    return;
  }
  const parentName = resolveSelectedParentId(normalizePersonName(parentSelect.value), state.branch);
  if (!parentName) {
    setWifeAlert("error", "اختر الأب أولاً.");
    return;
  }
  const husbandId = await getTreePersonIdByName(sb, parentName);
  if (!husbandId) {
    setWifeAlert("error", "تعذر تحديد رقم الأب في قاعدة البيانات.");
    return;
  }
  const name = normalizePersonName(wifeName && wifeName.value ? wifeName.value : "");
  if (!name) {
    setWifeAlert("error", "أدخل اسم الزوجة.");
    return;
  }
  const orderRaw = wifeOrder ? normalizeArabicDigitsToLatin(String(wifeOrder.value || "").trim()) : "";
  const order = orderRaw ? parseInt(orderRaw, 10) : null;
  if (orderRaw && (!order || order < 1 || order > 4)) {
    setWifeAlert("error", "ترتيب الزوجة يجب أن يكون من 1 إلى 4.");
    return;
  }
  const row = {
    husband_id: husbandId,
    wife_name: name,
    wife_is_family_member: parseWifeFamilyValue(),
    wife_branch_key: wifeBranch && wifeBranch.value ? String(wifeBranch.value).trim() : null,
    wife_lineage: wifeLineage && wifeLineage.value ? normalizePersonName(wifeLineage.value) : null,
    marriage_order: order,
    status: "active",
    confidence: "confirmed",
    data_source: "delegate",
    updated_at: new Date().toISOString()
  };
  const r = await sb.from("tree_spouses").insert(row).select("id").single();
  if (r.error) {
    setWifeAlert("error", "تعذر حفظ الزوجة: " + (r.error.message || "خطأ غير معروف"));
    return;
  }
  if (wifeName) wifeName.value = "";
  if (wifeFamily) wifeFamily.value = "";
  if (wifeBranch) wifeBranch.value = "";
  if (wifeOrder) wifeOrder.value = "";
  if (wifeLineage) wifeLineage.value = "";
  setWifeAlert("success", "تم حفظ الزوجة.");
  await loadWivesForSelectedParent();
}
async function linkChildToSelectedSpouse(childNodeId) {
  const spouseId = getSelectedChildSpouseId();
  if (!spouseId) return { ok: true };
  const sb = getالخدمةClient();
  if (!sb) return { ok: false, error: { message: "no client" } };
  const childId = await getTreePersonIdByName(sb, childNodeId);
  if (!childId) return { ok: false, error: { message: "تعذر تحديد رقم الابن بعد الحفظ." } };
  const spouse = await sb
    .from("tree_spouses")
    .select("id,wife_name,wife_is_family_member,wife_branch_key,wife_lineage,confidence")
    .eq("id", spouseId)
    .limit(1)
    .maybeSingle();
  if (spouse.error || !spouse.data) return { ok: false, error: spouse.error || { message: "تعذر تحميل بيانات الزوجة." } };
  const d = spouse.data;
  const r = await sb.from("tree_mother_links").upsert({
    child_id: childId,
    spouse_id: spouseId,
    mother_name: d.wife_name || null,
    mother_is_family_member: d.wife_is_family_member,
    mother_branch_key: d.wife_branch_key || null,
    mother_lineage: d.wife_lineage || null,
    confidence: d.confidence || "unknown",
    updated_at: new Date().toISOString()
  }, { onConflict: "child_id" });
  if (r.error) return { ok: false, error: r.error };
  return { ok: true };
}
